// ---------- Login BLoC ----------
class LoginState extends Equatable {
  final bool isLoading;
  final String? errorMessage;
  final bool success;

  const LoginState({
    this.isLoading = false,
    this.errorMessage,
    this.success = false,
  });

  LoginState copyWith({
    bool? isLoading,
    String? errorMessage,
    bool? success,
  }) {
    return LoginState(
      isLoading: isLoading ?? this.isLoading,
      errorMessage: errorMessage ?? this.errorMessage,
      success: success ?? this.success,
    );
  }

  @override
  List<Object?> get props => [isLoading, errorMessage, success];
}

abstract class LoginEvent extends Equatable {
  const LoginEvent();
  @override List<Object?> get props => [];
}

class LoginSubmitted extends LoginEvent {
  final String email;
  final String password;
  const LoginSubmitted(this.email, this.password);
  @override List<Object?> get props => [email, password];
}

class ClearError extends LoginEvent {}

class LoginBloc extends Bloc<LoginEvent, LoginState> {
  LoginBloc() : super(const LoginState()) {
    on<LoginSubmitted>(_onLoginSubmitted);
    on<ClearError>((event, emit) => emit(state.copyWith(errorMessage: null)));
  }

  Future<void> _onLoginSubmitted(LoginSubmitted event, Emitter<LoginState> emit) async {
    emit(state.copyWith(isLoading: true, errorMessage: null));
    await Future.delayed(Duration(seconds: 1));
    if (event.email == 'test@example.com' && event.password == 'password') {
      emit(state.copyWith(isLoading: false, success: true, errorMessage: null));
    } else {
      emit(state.copyWith(
        isLoading: false,
        errorMessage: 'Invalid credentials',
        success: false,
      ));
    }
  }
}

// ---------- UI ----------
class LoginPage extends StatelessWidget {
  final TextEditingController emailController = TextEditingController();
  final TextEditingController passwordController = TextEditingController();

  @override
  Widget build(BuildContext context) {
    return BlocProvider(
      create: (_) => LoginBloc(),
      child: Scaffold(
        appBar: AppBar(title: Text('Login Side Effects')),
        body: BlocListener<LoginBloc, LoginState>(
          listener: (context, state) {
            if (state.success) {
              Navigator.pushReplacementNamed(context, '/home');
            }
            if (state.errorMessage != null) {
              ScaffoldMessenger.of(context).showSnackBar(
                SnackBar(content: Text(state.errorMessage!)),
              );
              // Clear the error so it doesn't show again
              context.read<LoginBloc>().add(ClearError());
            }
          },
          child: BlocBuilder<LoginBloc, LoginState>(
            builder: (context, state) {
              return Padding(
                padding: const EdgeInsets.all(16.0),
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    TextField(
                      controller: emailController,
                      decoration: InputDecoration(labelText: 'Email'),
                    ),
                    TextField(
                      controller: passwordController,
                      obscureText: true,
                      decoration: InputDecoration(labelText: 'Password'),
                    ),
                    SizedBox(height: 20),
                    if (state.isLoading)
                      CircularProgressIndicator()
                    else
                      ElevatedButton(
                        onPressed: () {
                          context.read<LoginBloc>().add(LoginSubmitted(
                            emailController.text,
                            passwordController.text,
                          ));
                        },
                        child: Text('Login'),
                      ),
                    SizedBox(height: 20),
                    Text('Demo: test@example.com / password'),
                  ],
                ),
              );
            },
          ),
        ),
      ),
    );
  }
}

class HomePage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Home')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text('You are logged in!'),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: () => Navigator.pushReplacementNamed(context, '/'),
              child: Text('Logout'),
            ),
          ],
        ),
      ),
    );
  }
}
